translator.value:
@if(
    contains(item().name, 'performance'), 
    pipeline().parameters.performance_schema, 
    if(
        contains(item().name, 'campaign'), 
        pipeline().parameters.campaign_schema, 
        null
    )
)

p_filename.value:
@if(
    contains(item().name, 'performance'), 
    concat('social_post_performance_', formatDateTime(utcNow(), 'yyyyMMdd_HHmmss'), '_', item().name), 
    if(
        contains(item().name, 'campaign'), 
        concat('campaign_lookup_', formatDateTime(utcNow(), 'yyyyMMdd_HHmmss'), '_', item().name),
        concat('unclassified_', item().name)
    )
)
